 5→export function formatTime(timestamp: string | null): string {
 6→  if (!timestamp) return "";
 7→  const diff = Math.floor((Date.now() - new Date(timestamp).getTime()) / 1000);
 8→  if (diff < MINUTE) return "now";
 9→  if (diff < HOUR) return `${Math.floor(diff / MINUTE)}m`;
10→  if (diff < DAY) return `${Math.floor(diff / HOUR)}h`;
11→  return `${Math.floor(diff / DAY)}d`;
