31→export function formatDuration(seconds: number | null | undefined): string {
32→  if (!seconds || seconds <= 0) return "0s";
33→  const hours = Math.floor(seconds / HOUR);
34→  const minutes = Math.floor((seconds % HOUR) / MINUTE);
35→  const secs = Math.floor(seconds % MINUTE);
36→  const parts: string[] = [];
37→  if (hours > 0) parts.push(`${hours}h`);
38→  if (minutes > 0) parts.push(`${minutes}m`);
39→  if (secs > 0 || parts.length === 0) parts.push(`${secs}s`);
40→  return parts.join(" ");
41→}
