47→export function baseProjectName(path: string): string {
48→  if (!path) return "Unknown";
49→  const normalized = path.replace(/[\\/]+$/, "");
50→  const segments = normalized.split(/[\\/]/).filter(Boolean);
51→  const LAST_N_SEGMENTS = 2;
52→  if (segments.length === 0) return path;
53→  const tail = segments.slice(-LAST_N_SEGMENTS);
54→  return tail.join("/");
